from collections import deque
from typing import List

def solve(grid: List[List[int]]) -> int:
    R, C = len(grid), len(grid[0])
    if grid[0][0] or grid[R-1][C-1]:
        return -1
    q = deque([(0, 0, 1)])
    grid[0][0] = 1
    while q:
        r, c, d = q.popleft()
        if r == R-1 and c == C-1:
            return d
        for dr in [-1,0,1]:
            for dc in [-1,0,1]:
                nr, nc = r+dr, c+dc
                if 0<=nr<R and 0<=nc<C and not grid[nr][nc]:
                    grid[nr][nc] = 1
                    q.append((nr, nc, d+1))
    return -1
```

